import * as React from "react";
import { HashRouter } from "react-router-dom";
import { DataProvider } from "./rythme/data/data-provider";
import { AppShell } from "./rythme/components/AppShell/AppShell";
import { useGraphDashboard } from "./rythme/data/useGraphDashboard";
import {
  AuthView,
  ErrorView,
  LoadingView,
} from "./rythme/components/StateView/StateView";
import { mockData } from "./rythme/data/mock-data";
import { PolicyProvider, usePolicy } from "./rythme/config/PolicyProvider";
import { useTeamsToken } from "./useTeamsToken";
import "./rythme/styles/global.css";
import "./accompagnement/styles/tokens.css";

/** Propage le token Graph disponible vers le PolicyProvider. */
const PolicyTokenBridge: React.FC = () => {
  const auth = useTeamsToken();
  const { setToken } = usePolicy();
  React.useEffect(() => {
    if (auth.status === "ready" && auth.token) {
      setToken(auth.token);
    }
  }, [auth.status, auth.token, setToken]);
  return null;
};

/**
 * Racine du dashboard Rythme (v1.5 = timeline branchée sur Graph).
 *
 * - Leviers, IRA et annotations restent en mock (mockData)
 * - weeks.days sont hydratés via Graph (recovery + réunions futures)
 *
 * Le DataProvider reçoit toujours un DashboardData complet. Pendant le
 * chargement ou en erreur, on rend l'AppShell avec un placeholder d'état
 * à la place du RythmeTab — le topbar et les tabs restent visibles.
 *
 * v1.6 : ajout du router (HashRouter) pour supporter les sous-routes de
 * l'onglet Accompagnement (`/accompagnement/theme/:slug`, `/accompagnement/reco/:id`).
 * Le hash routing est choisi pour rester insensible au basename GitHub Pages.
 */
const DashboardApp: React.FC = () => {
  const dash = useGraphDashboard();

  // Choix du DashboardData à injecter dans le Provider :
  //   - ready : les vraies données fusionnées
  //   - sinon : le mock (pour que le Topbar affiche une date cohérente)
  const providerData = dash.data ?? mockData;

  return (
    <DataProvider data={providerData}>
      <AppShell dash={dash} />
    </DataProvider>
  );
};

/** State view rendu si dash.status !== ready. Exposé pour AppShell. */
export const DashboardStateView: React.FC<{
  dash: ReturnType<typeof useGraphDashboard>;
}> = ({ dash }) => {
  switch (dash.status) {
    case "loading":
      return <LoadingView />;
    case "authRequired":
      return <AuthView onSignIn={() => void dash.signIn()} />;
    case "error":
      return <ErrorView message={dash.error} onRetry={dash.retry} />;
    case "ready":
      return null;
  }
};

/**
 * Root exporté : encapsule le PolicyProvider au-dessus du DashboardApp pour
 * que `usePolicy()` soit disponible partout (orchestrateur Graph + onglet
 * QVCT). Le bridge propage le token Teams vers le provider dès qu'il est
 * disponible.
 */
const DashboardRoot: React.FC = () => (
  <HashRouter>
    <PolicyProvider>
      <PolicyTokenBridge />
      <DashboardApp />
    </PolicyProvider>
  </HashRouter>
);

export default DashboardRoot;
