/**
 * Politique QVCT — paramètres configurables par l'utilisateur qui pilotent
 * l'intégralité du calcul de l'IRA (4 facteurs), la détection des annotations,
 * et l'interprétation des leviers.
 *
 * Centralisation unique : aucun module consommateur ne doit hardcoder
 * les horaires de travail, les seuils de transition ou les pondérations.
 *
 * Persistance : via openTypeExtension "com.gr33t.policy" attachée à un
 * événement all-day "Gr33t Policy" (sentinelle au 1970-01-01) dans le
 * calendrier "Gr33t Recovery". Voir src/calendar/policyStorage.ts.
 */

export interface HourMinute {
  h: number; // 0..23
  m: number; // 0..59
}

export interface IraWeights {
  transitions: number;   // 0..1
  concentration: number; // 0..1
  horaires: number;      // 0..1
  focus: number;         // 0..1
}

export interface QvctPolicy {
  /** Heure de début de la plage de travail (incluse). */
  workStart: HourMinute;
  /** Heure de fin de la plage de travail (incluse). */
  workEnd: HourMinute;
  /** Pause minimale (min) AVANT une réunion pour qu'elle soit "correctement encadrée". Bornes 0-60. */
  transBeforeMin: number;
  /** Pause minimale (min) APRÈS une réunion pour qu'elle soit "correctement encadrée". Bornes 0-60. */
  transAfterMin: number;
  /** Pondérations IRA. Somme = 1 (exprimées en fraction). */
  weights: IraWeights;
}

export const DEFAULT_POLICY: QvctPolicy = {
  workStart: { h: 8, m: 0 },
  workEnd: { h: 18, m: 30 },
  transBeforeMin: 10,
  transAfterMin: 10,
  weights: {
    transitions: 0.30,
    concentration: 0.30,
    horaires: 0.25,
    focus: 0.15,
  },
};

// ─── Helpers dérivés ──────────────────────────────────────────────────────────

/** Minute absolue (0..1440) du début de plage de travail. */
export function workStartMin(p: QvctPolicy): number {
  return p.workStart.h * 60 + p.workStart.m;
}

/** Minute absolue (0..1440) de la fin de plage de travail. */
export function workEndMin(p: QvctPolicy): number {
  return p.workEnd.h * 60 + p.workEnd.m;
}

/** Seuil de pause avant réunion en millisecondes. */
export function transBeforeMs(p: QvctPolicy): number {
  return p.transBeforeMin * 60_000;
}

/** Seuil de pause après réunion en millisecondes. */
export function transAfterMs(p: QvctPolicy): number {
  return p.transAfterMin * 60_000;
}

// ─── Validation ───────────────────────────────────────────────────────────────

export type PolicyErrorKey =
  | "workStart"
  | "workEnd"
  | "workRange"
  | "transBeforeMin"
  | "transAfterMin"
  | "weights.transitions"
  | "weights.concentration"
  | "weights.horaires"
  | "weights.focus"
  | "weightsSum";

export interface PolicyValidation {
  ok: boolean;
  errors: Partial<Record<PolicyErrorKey, string>>;
}

function isInt(n: number): boolean {
  return Number.isFinite(n) && Math.floor(n) === n;
}

function validHourMinute(hm: HourMinute | undefined): boolean {
  return (
    !!hm &&
    isInt(hm.h) && hm.h >= 0 && hm.h <= 23 &&
    isInt(hm.m) && hm.m >= 0 && hm.m <= 59
  );
}

/**
 * Valide une politique QVCT.
 *
 * Règles :
 * - workStart et workEnd valides (h: 0-23, m: 0-59)
 * - workStart < workEnd (en minutes absolues)
 * - transBeforeMin et transAfterMin entiers dans [0, 60]
 * - chaque poids est un entier en pourcentage (0..100) — stocké en fraction (0..1)
 *   donc `weight × 100` doit être un entier
 * - somme des poids = 1 (tolérance ±0.001 pour flottants)
 */
export function validatePolicy(p: QvctPolicy): PolicyValidation {
  const errors: Partial<Record<PolicyErrorKey, string>> = {};

  if (!validHourMinute(p.workStart)) {
    errors.workStart = "Heure de début invalide.";
  }
  if (!validHourMinute(p.workEnd)) {
    errors.workEnd = "Heure de fin invalide.";
  }
  if (!errors.workStart && !errors.workEnd) {
    if (workStartMin(p) >= workEndMin(p)) {
      errors.workRange = "L'heure de début doit être avant l'heure de fin.";
    }
  }

  if (!isInt(p.transBeforeMin) || p.transBeforeMin < 0 || p.transBeforeMin > 60) {
    errors.transBeforeMin = "Entier entre 0 et 60 minutes.";
  }
  if (!isInt(p.transAfterMin) || p.transAfterMin < 0 || p.transAfterMin > 60) {
    errors.transAfterMin = "Entier entre 0 et 60 minutes.";
  }

  const wKeys: (keyof IraWeights)[] = ["transitions", "concentration", "horaires", "focus"];
  for (const k of wKeys) {
    const v = p.weights?.[k];
    if (typeof v !== "number" || !Number.isFinite(v) || v < 0 || v > 1) {
      errors[`weights.${k}` as PolicyErrorKey] = "Pourcentage entre 0 et 100.";
      continue;
    }
    // Doit représenter un entier en % (tolérance flottante)
    const pct = v * 100;
    if (Math.abs(pct - Math.round(pct)) > 1e-6) {
      errors[`weights.${k}` as PolicyErrorKey] = "Pourcentage entier uniquement.";
    }
  }

  if (Object.keys(errors).filter((k) => k.startsWith("weights.")).length === 0) {
    const sum =
      p.weights.transitions +
      p.weights.concentration +
      p.weights.horaires +
      p.weights.focus;
    if (Math.abs(sum - 1) > 0.001) {
      errors.weightsSum = "Le total doit être égal à 100 %.";
    }
  }

  return { ok: Object.keys(errors).length === 0, errors };
}

/** Clone profond d'une politique (utile pour les drafts d'édition). */
export function clonePolicy(p: QvctPolicy): QvctPolicy {
  return {
    workStart: { ...p.workStart },
    workEnd: { ...p.workEnd },
    transBeforeMin: p.transBeforeMin,
    transAfterMin: p.transAfterMin,
    weights: { ...p.weights },
  };
}

/** Égalité structurelle entre deux politiques. */
export function policiesEqual(a: QvctPolicy, b: QvctPolicy): boolean {
  return (
    a.workStart.h === b.workStart.h &&
    a.workStart.m === b.workStart.m &&
    a.workEnd.h === b.workEnd.h &&
    a.workEnd.m === b.workEnd.m &&
    a.transBeforeMin === b.transBeforeMin &&
    a.transAfterMin === b.transAfterMin &&
    a.weights.transitions === b.weights.transitions &&
    a.weights.concentration === b.weights.concentration &&
    a.weights.horaires === b.weights.horaires &&
    a.weights.focus === b.weights.focus
  );
}
