/**
 * Thématiques de l'onglet Accompagnement.
 *
 * Les 17 recos du brief sont réparties sur 4 thèmes. En v0, le thème
 * "collectif" est marqué `comingSoon: true` car ses 3 recos (10, 15, 16)
 * dépendent de signaux non encore captés (chats, manager, stockage).
 */

export type ThemeKey = "attention" | "reunions" | "recup" | "collectif";

export interface Theme {
  key: ThemeKey;
  /** Libellé long affiché dans la tuile et le bandeau de la page thématique. */
  label: string;
  /** Libellé court (tag dans la carte de reco). */
  short: string;
  /** Description en 1-2 lignes affichée dans la tuile. */
  description: string;
  /** Variable CSS de la couleur saturée (pastilles, filets, etc.). */
  colorVar: string;
  /** Variable CSS du fond "soft" (containers M3). */
  softVar: string;
  /** Variable CSS de la couleur d'encre sur le fond soft. */
  onVar: string;
  /** True si le thème n'a pas de reco active en v0. */
  comingSoon?: boolean;
}

