/** Lookup par id. */
export function findReco(id: number): Reco | undefined {
  return RECOS.find((r) => r.id === id);
}

/** Filtrage par thème. */
export function recosByTheme(theme: ThemeKey): Reco[] {
  return RECOS.filter((r) => r.theme === theme);
}
