import * as React from "react";
import { Link, useParams, useNavigate } from "react-router-dom";
import styles from "./ThemePage.module.css";
import { THEMES, type ThemeKey } from "../data/themes";
import { recosByTheme } from "../data/recos";
import { useStatuses } from "../data/statusStore";
import { RecoCard } from "../components/RecoCard/RecoCard";

type FilterKey = "all" | "lowEffort" | "highImpact" | "todo";
type SortKey = "impact" | "effort";

/**
 * Vue thématique. Liste les recos d'un thème avec filtres + tri.
 *
 * Filtres :
 *  - all       : toutes les recos du thème
 *  - lowEffort : effort ≤ 2
 *  - highImpact: impact ≥ 7
 *  - todo      : statut ≠ essayee
 *
 * Tris :
 *  - impact : impact desc
 *  - effort : effort asc
 */
export const ThemePage: React.FC = () => {
  const { slug } = useParams<{ slug: string }>();
  const navigate = useNavigate();
  const { statuses, setStatus } = useStatuses();
  const [filter, setFilter] = React.useState<FilterKey>("all");
  const [sort, setSort] = React.useState<SortKey>("impact");

  const themeKey = slug as ThemeKey;
  const theme = THEMES[themeKey];

  if (!theme || theme.comingSoon) {
    return (
      <div className={styles.root}>
        <div className={styles.notFound}>
          Thème inconnu ou pas encore disponible.{" "}
          <Link to="/accompagnement">← Retour</Link>
        </div>
      </div>
    );
  }

  const items = recosByTheme(themeKey);

  const filtered = React.useMemo(() => {
    let arr = [...items];
    if (filter === "lowEffort") arr = arr.filter((r) => r.effort <= 2);
    if (filter === "highImpact") arr = arr.filter((r) => r.impact >= 7);
    if (filter === "todo")
      arr = arr.filter((r) => statuses.get(r.id) !== "essayee");
    if (sort === "impact") arr.sort((a, b) => b.impact - a.impact);
    if (sort === "effort") arr.sort((a, b) => a.effort - b.effort);
    return arr;
  }, [items, filter, sort, statuses]);

  return (
    <div className={styles.root}>
      <nav className={styles.breadcrumb} aria-label="Fil d'Ariane">
        <button
          type="button"
          className={styles.crumbLink}
          onClick={() => navigate("/accompagnement")}
        >
          Accompagnement
        </button>
        <span className="material-symbols-rounded" aria-hidden>
          chevron_right
        </span>
        <span>{theme.label}</span>
      </nav>

      <div className={styles.head}>
        <span
          className={styles.dotLg}
          style={{ background: theme.colorVar }}
          aria-hidden
        />
        <h2 className={styles.h2}>{theme.label}</h2>
        <span className={styles.count}>
          {items.length} fiche{items.length > 1 ? "s" : ""}
        </span>
      </div>
      <p className={styles.desc}>{theme.description}</p>

      <div className={styles.filters}>
        <div className={styles.seg} role="tablist">
          {(
            [
              ["all", "Toutes"],
              ["lowEffort", "Effort faible"],
              ["highImpact", "Impact élevé"],
              ["todo", "À essayer"],
            ] as [FilterKey, string][]
          ).map(([k, label]) => (
            <button
              key={k}
              type="button"
              role="tab"
              aria-selected={filter === k}
              className={filter === k ? styles.segActive : ""}
              onClick={() => setFilter(k)}
            >
              {label}
            </button>
          ))}
        </div>
        <div className={styles.sortRow}>
          <span className={styles.sortLabel}>Trier :</span>
          <button
            type="button"
            className={`${styles.chip} ${sort === "impact" ? styles.chipOn : ""}`}
            onClick={() => setSort("impact")}
          >
            Impact ↓
          </button>
          <button
            type="button"
            className={`${styles.chip} ${sort === "effort" ? styles.chipOn : ""}`}
            onClick={() => setSort("effort")}
          >
            Effort ↑
          </button>
        </div>
      </div>

      {filtered.length === 0 ? (
        <div className={styles.empty}>
          Aucune recommandation ne correspond à ce filtre.
        </div>
      ) : (
        <div className={styles.grid}>
          {filtered.map((r) => (
            <RecoCard
              key={r.id}
              reco={r}
              status={statuses.get(r.id) ?? "new"}
              compact
              onMark={setStatus}
            />
          ))}
        </div>
      )}
    </div>
  );
};
