/**
 * Persistance des statuts de recos (localStorage).
 *
 * v0 : 3 statuts pris en charge :
 *   - "new"         (par défaut, pas en localStorage)
 *   - "essayee"     (l'utilisateur a marqué la reco comme essayée)
 *   - "pasPourMoi"  (l'utilisateur l'a écartée pour cette semaine)
 *
 * Sémantique de "pasPourMoi" non figée — pour l'instant, exclut la reco
 * des priorités au même titre que "essayee". Une expiration auto pourra
 * être ajoutée plus tard sans casser l'API.
 */

import * as React from "react";

export type RecoStatus = "new" | "essayee" | "pasPourMoi";

const STORAGE_KEY = "gr33t.acc.statuses.v1";

interface StoredEntry {
  status: Exclude<RecoStatus, "new">;
  /** ISO date à laquelle le statut a été posé (utile pour future expiration). */
  setAt: string;
}

type StoredMap = Record<string, StoredEntry>;

function readStore(): StoredMap {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return {};
    const parsed = JSON.parse(raw);
    return typeof parsed === "object" && parsed !== null ? parsed : {};
  } catch {
    return {};
  }
}

function writeStore(m: StoredMap): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(m));
  } catch {
    // localStorage indisponible ou plein → silent
  }
}

/** Lecture brute (snapshot, pas réactif). */
export function getStatus(id: number): RecoStatus {
  const entry = readStore()[String(id)];
  return entry?.status ?? "new";
}

/** Écriture. `status === "new"` supprime l'entrée (état par défaut). */
export function setStatus(id: number, status: RecoStatus): void {
  const map = readStore();
  if (status === "new") {
    delete map[String(id)];
  } else {
    map[String(id)] = { status, setAt: new Date().toISOString() };
  }
  writeStore(map);
  // Diffuse aux autres onglets / hooks de la même page
  window.dispatchEvent(new CustomEvent("gr33t.acc.statusesChanged"));
}

/** Snapshot complet (id → status). Utile pour le matching. */
export function getAllStatuses(): Map<number, RecoStatus> {
  const map = readStore();
  const out = new Map<number, RecoStatus>();
  for (const [k, v] of Object.entries(map)) {
    const id = Number(k);
    if (Number.isFinite(id)) out.set(id, v.status);
  }
  return out;
}

/**
 * Hook réactif : retourne la map des statuts + un setter qui met à jour
 * le storage et déclenche un re-render local. S'abonne aux changements
 * cross-composants via l'event `gr33t.acc.statusesChanged`.
 */
export function useStatuses(): {
  statuses: Map<number, RecoStatus>;
  setStatus: (id: number, status: RecoStatus) => void;
} {
  const [tick, setTick] = React.useState(0);
  React.useEffect(() => {
    const handler = () => setTick((t) => t + 1);
    window.addEventListener("gr33t.acc.statusesChanged", handler);
    // Storage event = changement déclenché par un autre onglet du navigateur
    window.addEventListener("storage", (e) => {
      if (e.key === STORAGE_KEY) handler();
    });
    return () => {
      window.removeEventListener("gr33t.acc.statusesChanged", handler);
    };
  }, []);
  const statuses = React.useMemo(() => getAllStatuses(), [tick]);
  const setter = React.useCallback((id: number, status: RecoStatus) => {
    setStatus(id, status);
  }, []);
  return { statuses, setStatus: setter };
}
