/**
 * Helpers partagés pour les appels directs Microsoft Graph (hors SDK).
 *
 * Utilisé par le dashboard v1.1 (policyStorage, scoreEventSync) qui font
 * du fetch() direct plutôt que de passer par @microsoft/microsoft-graph-client
 * (utilisé côté TaskPane legacy).
 */

const GRAPH_BASE = "https://graph.microsoft.com/v1.0";

export const GR33T_RECOVERY_CALENDAR_NAME = "Gr33t Recovery";

/** Catégories master utilisées pour tagger les events de focus. */
export const CATEGORY_FOCUS_DEEP = "Gr33t · Focus profond";
export const CATEGORY_FOCUS_PLAGE = "Gr33t · Plage focus";

interface GraphError {
  error?: { code?: string; message?: string };
}

/** Fetch authentifié vers Graph avec gestion d'erreurs standardisée. */
export async function graphFetch<T>(
  token: string,
  path: string,
  init: RequestInit = {}
): Promise<T> {
  const res = await fetch(`${GRAPH_BASE}${path}`, {
    ...init,
    headers: {
      Authorization: `Bearer ${token}`,
      Accept: "application/json",
      "Content-Type": "application/json",
      ...(init.headers ?? {}),
    },
  });
  if (!res.ok) {
    const body = (await res.json().catch(() => ({}))) as GraphError;
    const msg = body?.error?.message || `${res.status} ${res.statusText}`;
    const err = new Error(`Graph ${path}: ${msg}`) as Error & {
      status: number;
      code?: string;
    };
    err.status = res.status;
    err.code = body?.error?.code;
    throw err;
  }
  if (res.status === 204) return undefined as T;
  return (await res.json()) as T;
}

/**
 * S'assure que les 2 master categories Gr33t existent dans la mailbox du user.
 * Idempotent : crée uniquement celles qui manquent.
 *
 * Colors utilisées (presets Outlook) :
 *   - preset4 (Green)  → Focus profond (≥ 2h)
 *   - preset6 (Olive)  → Plage focus (30min–<2h)
 */
export async function ensureGr33tCategories(token: string): Promise<void> {
  interface Cat { id: string; displayName: string; color?: string }
  const resp = await graphFetch<{ value: Cat[] }>(
    token,
    "/me/outlook/masterCategories?$top=100"
  );
  const existing = new Set((resp.value ?? []).map((c) => c.displayName));
  const toCreate: { displayName: string; color: string }[] = [];
  if (!existing.has(CATEGORY_FOCUS_DEEP)) {
    toCreate.push({ displayName: CATEGORY_FOCUS_DEEP, color: "preset4" });
  }
  if (!existing.has(CATEGORY_FOCUS_PLAGE)) {
    toCreate.push({ displayName: CATEGORY_FOCUS_PLAGE, color: "preset6" });
  }
  for (const cat of toCreate) {
    await graphFetch(token, "/me/outlook/masterCategories", {
      method: "POST",
      body: JSON.stringify(cat),
    });
  }
}

/** Trouve ou crée le calendrier "Gr33t Recovery" et renvoie son id. */
export async function findOrCreateGr33tRecoveryCalendar(
  token: string
): Promise<string> {
  const resp = await graphFetch<{ value: { id: string; name: string }[] }>(
    token,
    "/me/calendars?$select=id,name&$top=100"
  );
  const found = resp.value?.find(
    (c) => c.name === GR33T_RECOVERY_CALENDAR_NAME
  );
  if (found) return found.id;
  const created = await graphFetch<{ id: string }>(token, "/me/calendars", {
    method: "POST",
    body: JSON.stringify({
      name: GR33T_RECOVERY_CALENDAR_NAME,
      color: "lightGreen",
    }),
  });
  return created.id;
}
