/**
 * Helpers de formatage d'un `WhyPayload` pour l'UI.
 *
 * Centralise la traduction "kind d'indicateur → comment l'afficher"
 * (libellé contextuel, valeur affichée, seuil affiché). Permet aux
 * composants de présentation (`RecoCard`, `WhyBlock`) de rester muets sur
 * la sémantique et de partager la même règle d'affichage.
 *
 * Cas particulier : pour les indicateurs binaires journaliers (débordements
 * `debord` / `chronique`), on convertit le pourcentage en "X jours /5",
 * plus parlant pour l'utilisateur (chaque jour = 20%). Le suffixe "/5" est
 * rendu en plus petit pour ne pas peser sur le chiffre principal.
 */

import * as React from "react";
import type { WhyPayload } from "./match";

export interface WhyDisplay {
  /** Affichage de la valeur (peut contenir un suffixe `<small>` pour "/5"). */
  valueDisplay: React.ReactNode;
  /** Libellé contextuel à droite de la valeur (mini-graph des cards). */
  contextLabel: string;
  /**
   * Libellé contextuel pour le bloc large (`WhyBlock` page détail), où
   * il y a plus de place pour expliciter. Si absent, fallback sur
   * `contextLabel`.
   */
  contextLabelLarge?: string;
  /** Affichage du seuil dans la ligne du bas. */
  thresholdDisplay: React.ReactNode;
  /** Unité utilisée par défaut pour la valeur (`%` ou `h`). */
  unit: string;
}

/** "/5" rendu en plus petit pour les indicateurs binaires journaliers. */
const SmallSuffix: React.FC<{ children: React.ReactNode }> = ({ children }) => (
  <span
    style={{
      fontSize: "0.65em",
      fontWeight: 600,
      opacity: 0.85,
      marginLeft: 2,
    }}
  >
    {children}
  </span>
);

export function formatWhy(why: WhyPayload): WhyDisplay {
  switch (why.kind) {
    case "debord":
    case "chronique": {
      // 100% débordements = 5 jours/5, 80% = 4j/5, etc. (palier de 20)
      const days = Math.round(why.value / 20);
      const thresholdDays = Math.round(why.threshold / 20);
      return {
        valueDisplay: (
          <>
            {days} jours<SmallSuffix>/5</SmallSuffix>
          </>
        ),
        contextLabel: "en débordement la semaine dernière",
        thresholdDisplay: (
          <>
            Seuil cible : {thresholdDays} jours<SmallSuffix>/5</SmallSuffix>
          </>
        ),
        unit: "%",
      };
    }
    case "volume":
      return {
        valueDisplay: `${why.value}h`,
        contextLabel: "cette semaine",
        thresholdDisplay: `Seuil cible : ${why.threshold}h`,
        unit: "h",
      };
    case "anticipation":
      return {
        valueDisplay: `${why.value}%`,
        contextLabel: "(volume de réunions comparé aux précédentes semaines)",
        contextLabelLarge:
          "de volume de réunions prévu cette semaine comparé aux 4 semaines précédentes",
        thresholdDisplay: `Seuil cible : ${why.threshold}%`,
        unit: "%",
      };
    case "multitache":
      return {
        valueDisplay: `${why.value}%`,
        contextLabel: "de multitâche permanent la semaine dernière",
        thresholdDisplay: `Seuil cible : ${why.threshold}%`,
        unit: "%",
      };
    case "enchainees":
      return {
        valueDisplay: `${why.value}%`,
        contextLabel: "de réunions enchaînées la semaine dernière",
        thresholdDisplay: `Seuil cible : ${why.threshold}%`,
        unit: "%",
      };
    default:
      // mtreunion, plages → affichage standard (à enrichir au fil de l'eau)
      return {
        valueDisplay: `${why.value}%`,
        contextLabel: "S-1",
        thresholdDisplay: `Seuil cible : ${why.threshold}%`,
        unit: "%",
      };
  }
}
