import * as React from "react";
import styles from "./IndicatorBar.module.css";

export interface IndicatorBarProps {
  /** Valeur observée (0-100 par défaut, ou en heures pour le volume). */
  value: number;
  /** Borne haute de la barre (typiquement 100). */
  max?: number;
  /** Seuil cible (au-dessus = mauvais, sauf si `inverse`). */
  threshold: number;
  /** Pour les indicateurs où "plus haut = mieux" (ex: plages de concentration). */
  inverse?: boolean;
  /** Libellé de contexte affiché à droite de la valeur. */
  label?: string;
  /** Suffixe d'unité après la valeur (ex: "%", "h"). */
  unit?: string;
  /**
   * Affichage personnalisé de la valeur (remplace `value + unit`). Permet
   * de présenter par exemple "4 jours /5" au lieu de "80 %" pour les
   * indicateurs binaires journaliers (débordements).
   */
  valueDisplay?: React.ReactNode;
  /**
   * Affichage personnalisé du seuil dans la ligne du bas (remplace
   * "Seuil cible : Xunit"). Optionnel.
   */
  thresholdDisplay?: React.ReactNode;
}

/**
 * Mini-graphe : valeur (couleur conditionnelle) + barre 6px + repère seuil
 * + ligne de méta. Utilisé dans la carte priorité (compact) et le bloc
 * "Pourquoi cette reco" de la page détail (large).
 */
export const IndicatorBar: React.FC<IndicatorBarProps> = ({
  value,
  max = 100,
  threshold,
  inverse = false,
  label,
  unit = "%",
  valueDisplay,
  thresholdDisplay,
}) => {
  const pct = Math.max(0, Math.min(100, (value / max) * 100));
  const overThreshold = inverse ? value < threshold : value > threshold;
  const color = overThreshold ? "var(--gr33t-pink)" : "var(--gr33t-green)";
  const thresholdPct = Math.max(0, Math.min(100, (threshold / max) * 100));

  return (
    <div className={styles.root}>
      <div className={styles.head}>
        <span className={styles.value} style={{ color }}>
          {valueDisplay ?? `${value}${unit}`}
        </span>
        {label && <span className={styles.label}>{label}</span>}
      </div>
      <div className={styles.track}>
        <div
          className={styles.threshold}
          style={{ left: `${thresholdPct}%` }}
          aria-hidden
        />
        <div
          className={styles.fill}
          style={{ width: `${pct}%`, background: color }}
        />
      </div>
      <div className={styles.foot}>
        <span>{thresholdDisplay ?? `Seuil cible : ${threshold}${unit}`}</span>
        <span>{overThreshold ? "Au-dessus" : "Sous le seuil"}</span>
      </div>
    </div>
  );
};
