/**
 * PolicyProvider — context React qui porte la politique QVCT active + l'API
 * de mise à jour.
 *
 * Flux :
 *   1. Au mount : lit `localStorage` pour un démarrage immédiat (fallback
 *      `DEFAULT_POLICY` si rien en cache).
 *   2. Quand un token Graph est fourni (via `setToken`) : recharge la
 *      politique depuis Graph et met à jour le cache.
 *   3. `save(next)` : valide, écrit dans Graph, met à jour le cache +
 *      l'état.
 *
 * Toute erreur de lecture Graph → on garde la valeur courante (cache ou
 * DEFAULT_POLICY) — jamais bloquant pour l'utilisateur.
 */
import * as React from "react";
import {
  DEFAULT_POLICY,
  clonePolicy,
  policiesEqual,
  validatePolicy,
  type QvctPolicy,
  type PolicyValidation,
} from "./policy";
import {
  readPolicyFromGraph,
  writePolicyToGraph,
} from "../../../calendar/policyStorage";

const STORAGE_KEY = "gr33t.policy.v1";

export type PolicyLoadStatus = "idle" | "loading" | "ready" | "error";
export type PolicySaveStatus = "idle" | "saving" | "saved" | "error";

export interface PolicyContextValue {
  policy: QvctPolicy;
  loadStatus: PolicyLoadStatus;
  saveStatus: PolicySaveStatus;
  loadError: string | null;
  saveError: string | null;
  /** Fournit le token Graph pour (re)lire la politique depuis Graph. */
  setToken: (token: string | null) => void;
  /** Sauve une nouvelle politique (Graph + cache local). Valide avant I/O. */
  save: (next: QvctPolicy) => Promise<void>;
  /** Validation de la politique active (ou d'un draft à valider). */
  validate: (p: QvctPolicy) => PolicyValidation;
}

const PolicyContext = React.createContext<PolicyContextValue | null>(null);

function loadFromStorage(): QvctPolicy | null {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== "object") return null;
    const v = validatePolicy(parsed as QvctPolicy);
    return v.ok ? clonePolicy(parsed as QvctPolicy) : null;
  } catch {
    return null;
  }
}

function saveToStorage(p: QvctPolicy): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(p));
  } catch {
    // Quota ou privacy mode — on ignore silencieusement
  }
}

export const PolicyProvider: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  // Initialisation synchrone depuis le cache (démarrage rapide)
  const [policy, setPolicy] = React.useState<QvctPolicy>(
    () => loadFromStorage() ?? clonePolicy(DEFAULT_POLICY)
  );
  const [loadStatus, setLoadStatus] = React.useState<PolicyLoadStatus>("idle");
  const [loadError, setLoadError] = React.useState<string | null>(null);
  const [saveStatus, setSaveStatus] = React.useState<PolicySaveStatus>("idle");
  const [saveError, setSaveError] = React.useState<string | null>(null);
  const [token, setTokenState] = React.useState<string | null>(null);

  // Reload depuis Graph quand un token est disponible
  React.useEffect(() => {
    if (!token) return;
    let cancelled = false;
    setLoadStatus("loading");
    setLoadError(null);
    void (async () => {
      try {
        const fromGraph = await readPolicyFromGraph(token);
        if (cancelled) return;
        if (fromGraph && !policiesEqual(fromGraph, policy)) {
          setPolicy(fromGraph);
          saveToStorage(fromGraph);
        }
        setLoadStatus("ready");
      } catch (err) {
        if (cancelled) return;
        setLoadError((err as Error).message || String(err));
        setLoadStatus("error");
      }
    })();
    return () => {
      cancelled = true;
    };
    // policy intentionnellement hors deps : seul le token déclenche le reload
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token]);

  const setToken = React.useCallback((t: string | null) => {
    setTokenState(t);
  }, []);

  const save = React.useCallback(
    async (next: QvctPolicy): Promise<void> => {
      const v = validatePolicy(next);
      if (!v.ok) {
        setSaveStatus("error");
        setSaveError("Politique invalide.");
        throw new Error("Politique invalide");
      }
      if (!token) {
        // Pas de token → on sauve local uniquement, le provider réessaiera
        // la persistence Graph au prochain token disponible. Pour l'instant
        // on considère ça comme une erreur pour forcer l'utilisateur à
        // réessayer une fois authentifié.
        setSaveStatus("error");
        setSaveError("Non authentifié — reconnectez-vous pour sauvegarder.");
        throw new Error("No Graph token available");
      }
      setSaveStatus("saving");
      setSaveError(null);
      try {
        await writePolicyToGraph(token, next);
        const cloned = clonePolicy(next);
        setPolicy(cloned);
        saveToStorage(cloned);
        setSaveStatus("saved");
      } catch (err) {
        setSaveError((err as Error).message || String(err));
        setSaveStatus("error");
        throw err;
      }
    },
    [token]
  );

  const validate = React.useCallback(
    (p: QvctPolicy) => validatePolicy(p),
    []
  );

  const value = React.useMemo<PolicyContextValue>(
    () => ({
      policy,
      loadStatus,
      saveStatus,
      loadError,
      saveError,
      setToken,
      save,
      validate,
    }),
    [policy, loadStatus, saveStatus, loadError, saveError, setToken, save, validate]
  );

  return (
    <PolicyContext.Provider value={value}>{children}</PolicyContext.Provider>
  );
};

/**
 * Hook qui renvoie la politique active + l'API. Si aucun `PolicyProvider`
 * n'est monté, renvoie une valeur dégradée basée sur DEFAULT_POLICY (pour
 * rester utilisable en tests unitaires isolés).
 */
export function usePolicy(): PolicyContextValue {
  const ctx = React.useContext(PolicyContext);
  if (ctx) return ctx;
  // Fallback pour environnements de test / isolés
  return {
    policy: clonePolicy(DEFAULT_POLICY),
    loadStatus: "idle",
    saveStatus: "idle",
    loadError: null,
    saveError: null,
    setToken: () => undefined,
    save: async () => {
      throw new Error("PolicyProvider non monté");
    },
    validate: (p) => validatePolicy(p),
  };
}
